#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10;

int n,m,a[N],f[N];
bool del[N];
priority_queue<pii,vector<pii>,greater<pii>> q[N];

int father(int x){
	return f[x]==x?x:f[x]=father(f[x]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        f[i]=i;
        q[i].push(make_pair(a[i],i));
    }
    while(m--){
        int op,x,y;
        scanf("%d%d",&op,&x);
        if(op==1){
            scanf("%d",&y);
            if(del[x] || del[y])
                continue;
            int fx=father(x),fy=father(y);
            if(fx!=fy){
                if(q[fx].size()<q[fy].size())
                    swap(fx,fy);
                f[fy]=fx;
                while(q[fy].size()){
                    q[fx].push(q[fy].top());
                    q[fy].pop();
                }
            }
        }else{
            if(del[x]){
                puts("-1");
                continue;
            }
            int fx=father(x);
            while(del[q[fx].top().y])
                q[fx].pop();
            printf("%d\n",q[fx].top().x);
            del[q[fx].top().y]=1;
            q[fx].pop();
        }
    }
    return 0;
}
